const App: React.FC = () => {
  const [activePage, setActivePage] = useState('dashboard');

  const renderContent = () => {
    switch (activePage) {
      case 'dashboard': return <Dashboard />;
      case 'cariler': return <Cariler />;
      case 'urunler': return <Urunler />;
      case 'siparisler': return <Siparisler />;
